{"code":"import json

filename = locals()['var_function-call-8531003678679978584']
with open(filename, 'r') as f:
    articles = json.load(f)

targets = [
    "U.S. Bounces Back to Beat Greece 77-71",
    "Pro tours: The stops and the talk",
    "DiMarco, Riley Play Way Into Ryder Cup (AP)",
    "Michael Phelps Wins Second Gold Medal (AP)",
    "U.S. Men Set World Record, Without Phelps"
]

print("__RESULT__:")
results = []
for art in articles:
    if art['title'] in targets:
        results.append({
            "title": art['title'],
            "len": len(art['description']),
            "desc_preview": art['description'][:50]
        })

# Also check for any other potential long sports article
# Filter by "Olympic" or "PGA" or "NBA" or "NFL" or "MLB"
others = []
for art in articles:
    text = (art['title'] + " " + art['description']).lower()
    if any(k in text for k in ['olympic', 'pga', 'nba', 'nfl', 'mlb']):
        others.append({
            "title": art['title'],
            "len": len(art['description'])
        })

others.sort(key=lambda x: x['len'], reverse=True)
# Add top 3 others to results
for o in others[:3]:
    if o['title'] not in targets:
        results.append(o)

print(json.dumps(results, indent=2))
"}

